#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    char M[1000001];
    int K;
    scanf("%s %d", M, &K);
    int len = strlen(M);
    int total = len * K;
    int count = 0;
    for (int i = 0; i < 10; i++) {
        for (int j = 0; j < 10; j++) {
            for (int k = 0; k < 10; k++) {
                int num = i * 100 + j * 10 + k;
                if (num % 3001 == 0) {
                    count++;
                }
            }
        }
    }
    printf("%d\n", count);
    return 0;
}

